import{_ as i,o as a,c as t,ag as h}from"./chunks/framework.CxZWPeXl.js";const d=JSON.parse('{"title":"Quản lý Giai đoạn","description":"","frontmatter":{},"headers":[],"relativePath":"admin-stages.md","filePath":"admin-stages.md"}'),o={name:"admin-stages.md"};function c(r,n,g,l,e,u){return a(),t("div",null,[...n[0]||(n[0]=[h('<h1 id="quan-ly-giai-đoan" tabindex="-1">Quản lý Giai đoạn <a class="header-anchor" href="#quan-ly-giai-đoan" aria-label="Permalink to &quot;Quản lý Giai đoạn&quot;">​</a></h1><blockquote><p>Xác định các giai đoạn thực hành bán hàng, thiết lập tiêu chuẩn và mục tiêu đánh giá.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Các giai đoạn bán hàng là nền tảng của bài thực hành. Mỗi giai đoạn đại diện cho một bước quyết định trong cuộc trò chuyện; AI sẽ theo dõi và đánh giá bạn dựa trên cấu hình này.</p><blockquote><p>Chỉ dành cho Quản trị viên.</p></blockquote><h2 id="cau-truc-giao-dien" tabindex="-1">Cấu trúc Giao diện <a class="header-anchor" href="#cau-truc-giao-dien" aria-label="Permalink to &quot;Cấu trúc Giao diện&quot;">​</a></h2><p>Trang quản lý hiển thị một danh sách các giai đoạn được sắp xếp theo số thứ tự (từ 1 đến 5 hoặc hơn):</p><ul><li><strong>Tiêu đề Thẻ</strong>: Định dạng &quot;Giai đoạn N: {Tên Giai đoạn}&quot; (có hỗ trợ hiển thị song ngữ, ví dụ tiếng Việt và tiếng Trung).</li><li><strong>Trạng thái Khách hàng (Mô tả)</strong>: Trạng thái tâm lý hoặc hành vi dự kiến của khách hàng trong bước này.</li><li><strong>Tùy chọn thao tác</strong>: Các nút biểu tượng để Chỉnh sửa (Edit) hoặc Xóa (Delete) giai đoạn.</li></ul><hr><h2 id="thuoc-tinh-giai-đoan" tabindex="-1">Thuộc tính Giai đoạn <a class="header-anchor" href="#thuoc-tinh-giai-đoan" aria-label="Permalink to &quot;Thuộc tính Giai đoạn&quot;">​</a></h2><h3 id="so-giai-đoan" tabindex="-1">Số Giai đoạn <a class="header-anchor" href="#so-giai-đoan" aria-label="Permalink to &quot;Số Giai đoạn&quot;">​</a></h3><ul><li>Xác định thứ tự diễn ra của giai đoạn. Phải là số nguyên dương và không được trùng lặp. Không thể sửa sau khi đã tạo.</li></ul><h3 id="ten-giai-đoan" tabindex="-1">Tên Giai đoạn <a class="header-anchor" href="#ten-giai-đoan" aria-label="Permalink to &quot;Tên Giai đoạn&quot;">​</a></h3><ul><li>Tên gọi chính thức của bước bán hàng (VD: 1. Phá băng, 2. Khám phá nhu cầu, 3. Chốt sale). Hỗ trợ nhập đa ngôn ngữ.</li></ul><h3 id="trang-thai-khach-hang-hien-tai" tabindex="-1">Trạng thái Khách hàng Hiện tại <a class="header-anchor" href="#trang-thai-khach-hang-hien-tai" aria-label="Permalink to &quot;Trạng thái Khách hàng Hiện tại&quot;">​</a></h3><ul><li>Mô tả dòng tâm lý của khách hàng để AI sử dụng làm tiêu chuẩn để đánh giá xem tư vấn viên đã vượt qua rào cản tâm lý này chưa. (VD: &quot;Khách hàng còn e ngại và chưa tin tưởng&quot;).</li></ul><hr><h2 id="thao-tac" tabindex="-1">Thao tác <a class="header-anchor" href="#thao-tac" aria-label="Permalink to &quot;Thao tác&quot;">​</a></h2><ul><li><strong>Thêm Giai đoạn (Add Stage)</strong>: Nhấp nút Thêm để điền Số, Tên, Mô tả bằng ngôn ngữ tương ứng.</li><li><strong>Chỉnh sửa</strong>: Nhấp biểu tượng cái bút trên thẻ (Lưu ý: Không sửa được Số Giai đoạn).</li><li><strong>Xóa</strong>: Nhấp biểu tượng thùng rác. Xóa giai đoạn có thể ảnh hưởng đến kết quả của các lịch sử thực hành trước đó.</li></ul><hr><h2 id="goi-y-thiet-ke-giai-đoan" tabindex="-1">Gợi ý Thiết kế Giai đoạn <a class="header-anchor" href="#goi-y-thiet-ke-giai-đoan" aria-label="Permalink to &quot;Gợi ý Thiết kế Giai đoạn&quot;">​</a></h2><ol><li><strong>Tiến trình hợp lý</strong>: Sắp xếp từ dễ đến khó, theo quy trình chốt sale thực tế.</li><li><strong>Mục tiêu rõ ràng</strong>: Mỗi giai đoạn nên có mục tiêu cụ thể, đo lường được để AI dễ dàng chấm điểm.</li><li><strong>Mô tả chân thực</strong>: Trạng thái tâm lý khách hàng phải phản ánh đúng thực tế.</li><li><strong>Số lượng vừa phải</strong>: Từ 3-7 giai đoạn là hợp lý nhất cho một phiên thực hành.</li></ol>',22)])])}const m=i(o,[["render",c]]);export{d as __pageData,m as default};
